/**
 * 200 micro-activities from the "200-Day Guide" ebook by un.shaped.
 * Used as the Spin Wheel activity pool.
 *
 * Source: 200-Day_Guide_Ebook_by_UnShaped.pdf
 */

export type SpinActivity = {
  day: number;
  title: string;
  instr: string;
};

export const SPIN_ACTIVITIES: SpinActivity[] = [
  { day: 1, title: 'DRINK YOUR COFFEE WITHOUT DOING ANYTHING ELSE AT THE SAME TIME', instr: 'Sit down with it. Phone somewhere else. Don\'t pair it with checking, scrolling, or reading. Drink it slow enough to notice you\'re drinking it.' },
  { day: 2, title: 'RATE EVERY CLOUD YOU SEE OUT OF TEN', instr: 'Go outside or find a window. Look up. Give each cloud a score out of ten. Be as serious or as ridiculous about it as you want. Spend at least five minutes on it.' },
  { day: 3, title: 'SIT IN SILENCE FOR TEN MINUTES. DON\'T FIX ANYTHING', instr: 'Find somewhere to sit. Set a timer for ten minutes. No music, no podcast, no phone. If a thought comes up that feels urgent, let it sit there. You don\'t have to do anything about it.' },
  { day: 4, title: 'TAKE PHOTOS OF BORING THINGS THAT FEEL WEIRDLY IMPORTANT', instr: 'Walk around your house or your neighbourhood. Photograph anything that catches your eye even slightly, no matter how mundane. A crack in the wall, the light on the counter, the way your shoes sit by the door. Don\'t post them.' },
  { day: 5, title: 'LISTEN TO A SONG. ONLY LISTEN', instr: 'Pick a song. Any song. Put headphones on if you can. Close your eyes if you want. Don\'t do anything else while it plays. Just listen to it like it\'s the only thing happening.' },
  { day: 6, title: 'GUESS WHAT TIME IT IS WITHOUT CHECKING. THEN CHECK HOW FAR OFF YOU WERE', instr: 'Before you look at your phone or a clock, guess the time. Then check. Do this a few times through the day.' },
  { day: 7, title: 'NOTICE FIVE THINGS YOU\'VE NEVER LOOKED AT IN YOUR OWN HOME', instr: 'Walk through your home slowly. Find five things you\'ve never actually paid attention to. A mark on a wall. The underside of a shelf. The way light hits a corner at this time of day. Stand with each one for a moment.' },
  { day: 8, title: 'LIE IN GRASS WITH NOTHING BETWEEN YOU AND THE GROUND', instr: 'Find some grass. Lie down on it. Stay there until you feel like getting up. Don\'t set a timer.' },
  { day: 9, title: 'DO ONE THING SLOWLY THAT YOU\'D NORMALLY FLY THROUGH IN MINUTES', instr: 'Pick something you usually rush. Folding a shirt. Making the bed. Washing a dish. Do it at half speed. Pay attention to each step like someone\'s filming a documentary about it.' },
  { day: 10, title: 'WALK INTO A ROOM AND FORGET WHY. STAY ANYWAY', instr: 'Next time you walk into a room and forget why you went in there, don\'t leave. Stay. Sit down if there\'s somewhere to sit. Look around for a minute. Then leave.' },
  { day: 11, title: 'EAT WITHOUT A SCREEN. TASTE THE FOOD', instr: 'Pick one meal today. Eat it without your phone, a laptop, a TV, or anything else to look at. Just eat.' },
  { day: 12, title: 'COUNT HOW MANY SOUNDS YOU CAN HEAR RIGHT NOW', instr: 'Wherever you are, stop and listen. Count every individual sound you can identify. The fridge humming. Traf c outside. Your own breathing. A bird. A pipe. Keep going until you run out.' },
  { day: 13, title: 'SCROLL YOUR CAMERA ROLL. NOTICE THE PATTERNS YOU DIDN\'T CHOOSE', instr: 'Open your photos. Start from three or four months ago. Scroll slowly. Don\'t delete anything. Just notice what you photographed, who shows up, what\'s missing, what you chose to save.' },
  { day: 14, title: 'SEE HOW MANY TEXTURES YOU CAN FEEL IN ONE ROOM', instr: 'Pick a room. Touch as many different surfaces as you can. The wall, the fabric on a chair, the cold of a window, the grain of wood, the smooth of a screen. Count them.' },
  { day: 15, title: 'WALK SOMEWHERE WITHOUT DECIDING WHERE. NO HEADPHONES', instr: 'Leave your house. Don\'t decide where you\'re going. Let the route decide itself. Walk until you feel like turning around.' },
  { day: 16, title: 'EAT SOMETHING WITH YOUR HANDS THAT DOESN\'T REQUIRE HANDS', instr: 'Pick a food you\'d normally eat with a fork or spoon. Eat it with your hands instead. A bowl of pasta, a salad, rice. Commit to it fully.' },
  { day: 17, title: 'COOK SOMETHING SLOW. NO RECIPE, NO SCREEN', instr: 'Pick something simple to cook. Leave the phone elsewhere and nothing on in the background. Just cook, paying attention to the heat, the smell, the sound of it.' },
  { day: 18, title: 'SAY OUT LOUD THE THING YOU\'VE BEEN AVOIDING', instr: 'Find somewhere private. Say the thing you keep circling around but won\'t name. Out loud, not in your head. It might be small or enormous. Just say it so the air hears it.' },
  { day: 19, title: 'TRY TO WHISTLE A SONG YOU LOVE', instr: 'Pick a song you know well. Try to whistle the melody. Sit with whatever happens. Notice how fast you want to quit, and whether it\'s because of skill or because something in you says it\'s silly.' },
  { day: 20, title: 'SIT ON A BENCH AND WATCH PEOPLE WITHOUT MAKING IT WEIRD', instr: 'Find a bench in a public place. Sit there. Watch people walk past without staring. Don\'t make up stories about them. Just observe how they move, what they carry, how fast they walk.' },
  { day: 21, title: 'RE-READ SOMETHING YOU WROTE YEARS AGO. TRY NOT TO CRINGE', instr: 'Find an old journal, a note on your phone from years ago, an email you sent, a school essay, anything you wrote when you were a different person. Read it slowly.' },
  { day: 22, title: 'BALANCE SOMETHING ON YOUR HEAD AND WALK ACROSS THE ROOM', instr: 'Pick an object. A book, a cushion, a shoe. Balance it on your head and walk across the room without it falling. If it falls, start over.' },
  { day: 23, title: 'SMELL SOMETHING AND TRY TO DESCRIBE IT WITHOUT USING THE WORD "LIKE."', instr: 'Pick something with a strong smell. Coffee, a candle, rain on concrete, an old book. Smell it. Try to describe it using only direct language, no similes, no "it smells like."' },
  { day: 24, title: 'SPY ON AN INANIMATE OBJECT WITHOUT IT CATCHING YOU', instr: 'Pick an object in your house. A mug, a chair, a plant. Watch it for two minutes as if it\'s alive and you don\'t want it to know you\'re looking. Be as serious about this as you can manage.' },
  { day: 25, title: 'STARE AT SOMETHING ORDINARY UNTIL IT GETS INTERESTING', instr: 'Pick the most boring object in your immediate view. A wall, a table leg, a door handle. Stare at it without looking away. Wait until something about it becomes interesting.' },
  { day: 26, title: 'DRAW SOMETHING BADLY ON PURPOSE', instr: 'Get a pen and paper. Draw something. A face, a tree, your hand, anything. Draw it badly. Don\'t try to make it good. If it starts looking decent, make it worse.' },
  { day: 27, title: 'NOTICE HOW OFTEN YOU FILL SILENCE JUST BECAUSE IT\'S THERE', instr: 'For one full hour, pay attention to every time you reach for noise. Turning on music, opening an app, starting a conversation, humming, anything. Don\'t stop yourself from doing it. Just notice each time.' },
  { day: 28, title: 'GO OUTSIDE BEFORE MOST PEOPLE ARE AWAKE', instr: 'Set an alarm early enough that the streets are empty. Go outside. You don\'t have to do anything. Just be outside in the version of the world that exists before everyone else wakes up.' },
  { day: 29, title: 'STARE AT THE MOON LIKE YOU\'RE IN A MUSIC VIDEO', instr: 'Go outside at night. Find the moon. Stand there and look at it like it means something. Be dramatic about it. Lean on something. Let the wind hit your face. Commit to the moment.' },
  { day: 30, title: 'CLEAN ONE SMALL AREA LIKE IT\'S THE ONLY THING THAT EXISTS', instr: 'Pick a small space. A single shelf, one section of a counter, the area around your sink. Clean it slowly and thoroughly as if nothing else in the world needs your attention.' },
  { day: 31, title: 'ACT WEIRD ON PURPOSE UNTIL YOU MAKE YOURSELF LAUGH', instr: 'When you\'re alone, do something deliberately strange. Walk in an exaggerated way, make a face in the mirror, talk to yourself in an accent. Do it until you actually laugh. Not a polite exhale, a real laugh.' },
  { day: 32, title: 'NOTICE WHAT YOU FEEL WHEN ABSOLUTELY NO ONE IS WATCHING', instr: 'Find a moment when you\'re completely alone. No one in the room, no one about to walk in, no one waiting on a text. Sit in that aloneness and pay attention to what your body does, not what you think but what you feel.' },
  { day: 33, title: 'HAVE A FULL CONVERSATION WITH YOUR PET LIKE THEY UNDERSTAND ECONOMICS', instr: 'If you have a pet, sit down with them and explain something complex. The housing market, in ation, your tax situation. Be thorough. If you don\'t have a pet, explain it to a plant or an object.' },
  { day: 34, title: 'WALK A ROUTE YOU\'VE NEVER TAKEN', instr: 'Leave your house. Turn a different direction than you normally would. Walk a route you\'ve never walked before. Pay attention to what you see.' },
  { day: 35, title: 'WATCH YOUR OWN THOUGHTS LIKE YOU\'RE EAVESDROPPING ON A STRANGER', instr: 'Sit somewhere quiet for five minutes. Instead of thinking, watch your thoughts as if they belong to someone else. Don\'t follow them, argue with them, or try to x them. Just observe what comes through.' },
  { day: 36, title: 'LET YOUR TEA GO COLD ON PURPOSE. DRINK IT ANYWAY', instr: 'Make tea or coffee. Set it down. Don\'t drink it until it\'s cold. Then drink it.' },
  { day: 37, title: 'MAKE SOMETHING WITH YOUR HANDS. NO PURPOSE REQUIRED', instr: 'Find materials. Paper, clay, sticks, old boxes, tape, anything. Make something. It doesn\'t need to be good or recognizable. Just use your hands to create a thing that didn\'t exist before.' },
  { day: 38, title: 'SIT WITH A QUESTION INSTEAD OF RACING TO SOLVE IT', instr: 'Think of a question you\'ve been turning over in your head. One you don\'t have an answer to. Sit with it for five minutes. Don\'t try to answer it or Google it or ask anyone. Just hold the question and let it be unanswered.' },
  { day: 39, title: 'SEE HOW LONG YOU CAN STAND ON ONE FOOT WITH YOUR EYES CLOSED', instr: 'Stand up. Close your eyes. Lift one foot off the ground. Try to stay balanced. Time yourself if you want.' },
  { day: 40, title: 'KILL ALL NOTIFICATIONS FOR A FEW HOURS', instr: 'Go into your phone settings. Turn off all noti cations. All of them. Leave it that way for at least three hours. Don\'t check your phone unless you decide to. Let the decision be yours, not the phone\'s.' },
  { day: 41, title: 'CALL SOMEONE AND BE PRESENT INSTEAD OF EFFICIENT', instr: 'Call someone you care about. Not text, call. When they answer, don\'t rush to the point or multitask. Just talk and let the conversation go wherever it goes.' },
  { day: 42, title: 'TRACE THE OUTLINE OF YOUR HAND LIKE YOU\'RE SEVEN AGAIN', instr: 'Get a piece of paper and a pen. Put your hand at on the paper. Trace around it slowly. Look at the drawing when you\'re done.' },
  { day: 43, title: 'REARRANGE A CORNER OF YOUR SPACE UNTIL IT FEELS LIKE YOURS AGAIN', instr: 'Pick one small area of your home that feels off. A desk, a shelf, a bedside table. Move things around until it feels right. Not perfect, just yours.' },
  { day: 44, title: 'LEARN ONE THING FOR NO CAREER REASON WHATSOEVER', instr: 'Spend thirty minutes learning something that will never help your career, never make you money, never go on a CV. The history of a country you\'ll never visit, how a violin is made, what clouds are actually called. Learn it because it\'s interesting.' },
  { day: 45, title: 'TRY TO FOLD A FITTED SHEET. ACCEPT DEFEAT GRACEFULLY', instr: 'Get a tted sheet. Try to fold it properly. Flat edges, clean corners, no bunching. When it inevitably doesn\'t work, accept the result and put it away. Why this works. This is a practice in accepting imperfection inside a task famously impossible to do well. Everyone folds tted sheets badly. The question is whether you can do something badly, know it\'s bad, and be ne. Most people either avoid what they can\'t perfect or obsess over getting it right. The middle ground, doing it imperfectly and moving on, applies to almost everything in your life. Did you try to get it perfect, or were you able to let it be messy and move on? WHAT DID YOU NOTICE? WHAT DID YOU FEEL? ANYTHING ELSE? fi fi fi' },
  { day: 46, title: 'WRITE DOWN WHAT YOU WANT WITHOUT MAKING IT SOUND REASONABLE', instr: 'Get a piece of paper. Write down what you want. Not the version you\'d tell someone at dinner or the one that sounds achievable. The real one, the one you\'d be embarrassed to say because it sounds too big or too simple or too honest.' },
  { day: 47, title: 'WATCH ANTS. THEY HAVE THEIR WHOLE THING GOING ON', instr: 'Find some ants. A trail on the pavement, a few on a wall, wherever. Watch them for five minutes. Follow one and see where it goes.' },
  { day: 48, title: 'WATCH HOW FAST YOUR BRAIN TRIES TO ESCAPE STILLNESS', instr: 'Sit somewhere with nothing to do. No phone or book to reach for. Set a timer for ten minutes and just sit. But this time, instead of trying to be still, watch how aggressively your brain tries to escape the stillness. Count the escape attempts.' },
  { day: 49, title: 'STUDY YOUR OWN HABITS LIKE A STRANGER WOULD', instr: 'For a day, observe your habits as if you\'re a researcher studying someone you\'ve never met. Notice what they do first thing, what they reach for, how they eat, when they check their phone. Don\'t change anything. Just document.' },
  { day: 50, title: 'NOTICE WHAT RELIEF FEELS LIKE WHEN YOU STOP TRYING', instr: 'At some point today, stop trying. Whatever you\'re working on, whatever you\'re pushing through, put it down for five minutes. Not for a break, but to feel what relief actually feels like in your body. Where does it land? In your shoulders, jaw, chest?' },
  { day: 51, title: 'WALK IN THE RAIN WITHOUT RUSHING TO GET OUT OF IT', instr: 'Next time it rains, go outside. Walk at normal speed. Don\'t run or hunch or duck for shelter. Just walk in it and feel what the rain actually feels like on your skin and clothes.' },
  { day: 52, title: 'DANCE ALONE. BADLY. FULLY COMMITTED', instr: 'Put on any song. Dance to it badly, with no awareness of how you look. Dance the way you would if no one had ever told you how dancing was supposed to look. Commit fully. Arms, legs, everything.' },
  { day: 53, title: 'SAY NO TO PLANS YOU ALREADY RESENT', instr: 'Think of something you\'ve agreed to that you don\'t actually want to do. A dinner, a call, a commitment that lled you with quiet dread when you said yes. Cancel it. You don\'t have to explain beyond "I can\'t make it."' },
  { day: 54, title: 'TAKE A LONG SHOWER AND JUST THINK', instr: 'Take a shower. Longer than usual. No music or podcast or audiobook. Just you and the water and whatever thoughts show up.' },
  { day: 55, title: 'LAY ON THE FLOOR AND LET YOUR DOG THINK SOMETHING IS WRONG', instr: 'Lie at on the floor. If you have a dog, let them investigate. If you don\'t have a dog, just lie there anyway. Stay for at least five minutes. Why this works. The floor is not where adults usually go. It\'s for children and for emergencies. Lying on it for no reason puts your body in an unfamiliar position, which puts your brain in one too. The perspective changes, the ceiling closer, the furniture different. Your dog\'s confusion is just a bonus. The actual value is doing something your body doesn\'t expect and noticing how the world rearranges. Echoes Day 70. The floor again, with a different setup. What looked different from down there? WHAT DID YOU NOTICE? WHAT DID YOU FEEL? ANYTHING ELSE? fl fl fl fl fi' },
  { day: 56, title: 'WRITE ONE HONEST PAGE YOU\'D NEVER SHOW ANYONE', instr: 'Get paper. Write one full page. It can be about anything. The only rule is that it\'s honest and you\'ll never show it to anyone. Just one page of whatever is actually true right now.' },
  { day: 57, title: 'STACK ROCKS FOR NO REASON', instr: 'Find some rocks. Stack them. One on top of another. See how high you can go before they fall. When they fall, start again.' },
  { day: 58, title: 'WEAR SOMETHING YOU LIKE THAT NOBODY ELSE WOULD PICK FOR YOU', instr: 'Open your wardrobe. Find the thing you like that doesn\'t match what people expect, the colour that\'s too bold, the item that doesn\'t t your usual look. Wear it today. All day.' },
  { day: 59, title: 'WAKE UP AND DO NOTHING PRODUCTIVE FOR THE FIRST HOUR', instr: 'When you wake up tomorrow, don\'t do anything useful for sixty minutes. Skip email, lists, cleaning, planning. Sit with your coffee. Look out the window. Let the first hour belong to you instead of your responsibilities.' },
  { day: 60, title: 'WALK BACKWARDS FOR AS LONG AS YOU CAN WITHOUT HITTING SOMETHING', instr: 'Find an open space. Walk backwards. Pay attention to what\'s behind you without turning around. See how far you get before you need to stop or check.' },
  { day: 61, title: 'LET SOMEONE ELSE BE RIGHT WITHOUT CORRECTING THEM', instr: 'At some point today, someone will say something you know is wrong or slightly off. A fact, an opinion, a story with a detail out of place. Let it go. Don\'t correct it or mention it later. Just let them be right.' },
  { day: 62, title: 'GO TO A CAFE ALONE. PHONE STAYS IN THE BAG', instr: 'Go to a cafe by yourself. Order something. Sit down. Your phone stays in your bag or your pocket for the entire time. Look around, watch people, drink your drink. Be a person sitting in a cafe.' },
  { day: 63, title: 'SPEND MONEY ON SOMETHING USELESS THAT MAKES YOU HAPPY', instr: 'Buy something that serves no purpose. A weird mug, a single ower, a pen that\'s nicer than it needs to be. Something that exists purely because it makes you feel something.' },
  { day: 64, title: 'WATCH YOUR REACTIONS WITHOUT BUILDING A CASE FOR THEM', instr: 'For one hour today, pay attention to your emotional reactions. A comment, a headline, a text, a delay. Notice the reaction, then don\'t do anything with it. Don\'t build an argument or rehearse what you\'d say. Just notice it and let it sit.' },
  { day: 65, title: 'WATCH AN ENTIRE SUNSET WITHOUT PICKING UP YOUR PHONE ONCE', instr: 'Find a sunset. Sit or stand where you can see the whole thing. Watch it from start to finish. Don\'t photograph, lm, or text anyone about it. Just watch it happen.' },
  { day: 66, title: 'SKIP A STONE, OR JUST THROW ROCKS AT WATER', instr: 'Find water and some rocks. Throw them. If you can skip a stone, try to beat your record. If you can\'t, throw them in and watch the splash. Either way, keep going until your arm gets tired.' },
  { day: 67, title: 'TYPE FOR TEN MINUTES WITHOUT STOPPING OR GOING BACK', instr: 'Open a blank document or piece of paper. Set a timer for ten minutes. Start writing. Don\'t stop, x typos, or go back. If you have nothing to say, write "I have nothing to say" until something else comes.' },
  { day: 68, title: 'NAME WHAT DRAINS YOU. STOP PRETENDING IT DOESN\'T', instr: 'Get a piece of paper. Write the heading "Things that drain me." List them. People, habits, obligations, environments, patterns. Be specific. Don\'t soften them or add "but I know it\'s important" or "but they mean well." Just name the drain.' },
  { day: 69, title: 'TRY TO HUM AND WHISTLE AT THE SAME TIME', instr: 'Try it right now. Hum and whistle at the same time. Spend at least two minutes on this.' },
  { day: 70, title: 'SIT ON THE FLOOR FOR NO REASON. STAY THERE', instr: 'Find a spot on the floor. Sit down. Stay for at least five minutes. You don\'t have to meditate or do anything. Just sit on the floor like you used to before someone told you that chairs were for adults.' },
  { day: 71, title: 'FORGIVE SOMEONE IN YOUR HEAD. DON\'T TELL THEM', instr: 'Think of someone you\'ve been holding something against. It doesn\'t need to be dramatic. A small resentment counts. Forgive them fully in your head, and let it go. Don\'t tell them you did it.' },
  { day: 72, title: 'PICK A STRANGER AND INVENT THEIR ENTIRE BACKSTORY', instr: 'Next time you\'re in public, pick someone you don\'t know. Invent their life. Name, job, what they had for breakfast, what they\'re worried about, what they\'re walking toward. Be generous with the details.' },
  { day: 73, title: 'LISTEN TO AN ALBUM FRONT TO BACK LIKE IT\'S 2009', instr: 'Pick an album, not a playlist. Put it on from the first track and listen to the last. Don\'t skip or shuf e. Let it play in the order someone intended. Why this works. Albums were designed as sequences. Each track is where it is because someone decided the one before builds to it. Playlists and shuf e destroyed that architecture. Listening in order is like reading a book instead of random pages. You hear transitions, feel the arc, the experience has shape. That shape is something your brain has been missing. A beginning, middle, and end someone else built for you. What did you hear in the sequence that you would have missed on shuf e? WHAT DID YOU NOTICE? WHAT DID YOU FEEL? ANYTHING ELSE? fl fl fl fi' },
  { day: 74, title: 'LEAVE A CONVERSATION BEFORE YOU\'VE SAID TOO MUCH', instr: 'The next time you\'re in a conversation and you feel the urge to keep talking, to add one more point, to ll the silence, stop. Leave the conversation at that point. Before the over-explanation. Just stop.' },
  { day: 75, title: 'ASK YOURSELF WHAT YOU\'D DO IF NOBODY EVER FOUND OUT', instr: 'Sit with this question for five minutes. If you could do anything, take any action, make any change, pursue any path, and nobody would ever know, what would you do? Don\'t censor it or judge it. Let the answer arrive on its own.' },
  { day: 76, title: 'HOLD A PLANK UNTIL YOUR BODY PERSONALLY ASKS YOU TO STOP', instr: 'Get into a plank position. Hold it. Don\'t set a timer. Don\'t aim for a number. Just hold it until your body tells you clearly that it\'s done. Then hold it for three more seconds and stop.' },
  { day: 77, title: 'STAND IN A BOOKSHOP WITH NO AGENDA', instr: 'Go to a bookshop. Don\'t look for anything specific or check bestseller lists or head to your usual section. Walk around. Pick things up because they look interesting. Read a paragraph from the middle. Put it back. Pick up another one.' },
  { day: 78, title: 'FINISH A DAY WITHOUT CHECKING HOW ANYONE ELSE SPENT THEIRS', instr: 'Go a full day without looking at anyone\'s social media, stories, posts, or updates. You can use your phone and text people. But no feeds. No checking what anyone else did today. Just live your day and let everyone else live theirs without watching.' },
  { day: 79, title: 'SPEND AN HOUR CONSUMING NOTHING', instr: 'Set a timer for one hour. During that hour, consume nothing. No eating, no drinking (water is ne), no reading, no watching, no scrolling, no listening, no music. You can move around or sit or stare at a wall. But nothing goes in.' },
  { day: 80, title: 'EAT WITH A UTENSIL YOU DON\'T NORMALLY USE', instr: 'Pick a meal today and eat it with the utensil you don\'t normally use. If you always use a fork, use chopsticks. If you use your hands, try a knife and fork. Make the simple thing awkward on purpose.' },
  { day: 81, title: 'PICK A RANDOM WORD AND WRITE EVERYTHING IT REMINDS YOU OF', instr: 'Open a book or a dictionary to a random page. Point at a word without looking. Write that word at the top of a page. Then write everything it reminds you of. Memories, people, feelings, images, sounds, other words. Keep going until you run out.' },
  { day: 82, title: 'NOTICE WHERE YOUR BODY HOLDS TENSION. DON\'T GOOGLE IT', instr: 'Scan your body from head to feet. Find where you\'re holding tension. Your jaw, your shoulders, your hands, your lower back. Just notice it. Don\'t try to x it or look up what it means. Just know it\'s there.' },
  { day: 83, title: 'JOURNAL ABOUT WHO YOU WERE BEFORE YOU STARTED PERFORMING', instr: 'Write about who you were before you started curating yourself for other people. Before you learned what was acceptable, impressive, attractive, correct. Before you gured out which version got the best response.' },
  { day: 84, title: 'TRY TO BALANCE A SPOON ON YOUR NOSE', instr: 'Get a spoon. Try to balance it on your nose. That\'s it. Keep trying until you can hold it for at least five seconds, or until you\'ve been trying for ten minutes, whichever comes first.' },
  { day: 85, title: 'CANCEL A PLAN AND DON\'T REPLACE IT WITH ANOTHER ONE', instr: 'Pick something you have planned this week. Something optional, not a work obligation. Cancel it. And then don\'t ll the gap with anything else. Leave the space empty. Let the evening or the afternoon just be whatever it ends up being.' },
  { day: 86, title: 'COUNT YOUR BREATHS UNTIL YOU LOSE COUNT, THEN START OVER', instr: 'Sit somewhere quiet. Close your eyes if you want. Count your breaths. Inhale is one, exhale is two. At some point your mind will wander and you\'ll lose the number. When that happens, start over from one. Keep going for ten minutes.' },
  { day: 87, title: 'GUESS WHAT YOUR NEIGHBOURS ARE DOING RIGHT NOW. BE GENEROUS', instr: 'Wherever you are, think about the people on the other side of your walls. Imagine what they\'re doing right now. Be generous about it. Assume the best version of their evening. Assume they\'re doing something kind or funny or ordinary and good.' },
  { day: 88, title: 'WATCH SOMETHING THAT MAKES YOU CRY. DON\'T SKIP PAST IT', instr: 'Pick a lm, a scene, a documentary, a video. Something you know will make you emotional. Watch it. When the feeling comes, don\'t skip forward or check your phone or laugh it off. Just let it happen.' },
  { day: 89, title: 'SIT SOMEWHERE UNFAMILIAR. STAY LONGER THAN FEELS COMFORTABLE', instr: 'Go to a place you\'ve never sat before. A bench in a different part of town, a park you\'ve driven past, a waiting room you have no appointment in. Sit down. Stay for at least twenty minutes. Don\'t pretend to be busy.' },
  { day: 90, title: 'WRITE DOWN WHAT YOU ALREADY KNOW BUT KEEP IGNORING', instr: 'Sit with a piece of paper. Write down the things you already know are true that you keep choosing not to act on. The thing you should have said, the truth you keep walking past because dealing with it would be inconvenient.' },
  { day: 91, title: 'ARGUE WITH YOURSELF ABOUT SOMETHING STUPID. LET THE OTHER SIDE WIN', instr: 'Pick something you have a mild opinion about. Pineapple on pizza, cats vs dogs, socks with sandals. Now argue the opposite side, out loud or on paper. Argue it seriously and let the other side win.' },
  { day: 92, title: 'DELETE AN APP FOR A WEEK AND SEE WHAT REPLACES IT', instr: 'Pick the app you open most without thinking. Delete it. This isn\'t a detox, just an experiment in what your hands do when the thing they reach for isn\'t there. Leave it deleted for seven days.' },
  { day: 93, title: 'PICK A WALL IN YOUR HOME. ACTUALLY LOOK AT IT', instr: 'Choose a wall you face every day. Look at it like you\'ve never seen it. The colour, the texture, the marks, the way light hits it. The things hung on it and whether you chose them or they just ended up there.' },
  { day: 94, title: 'FOLLOW AN ANT FOR FIVE MINUTES', instr: 'Find an ant and follow it. Watch where it goes, what it carries, what it walks around, what it walks over. Don\'t interfere or redirect it. Just follow for at least five minutes.' },
  { day: 95, title: 'NARRATE YOUR OWN LIFE IN THIRD PERSON FOR FIVE MINUTES', instr: 'For the next five minutes, narrate everything you\'re doing as if you\'re a character in a book. "She walked to the kitchen. She opened the fridge and stood there for longer than necessary." Out loud or in your head. Keep it going. Why this works. Third person creates distance between you and your actions. Instead of being the person doing the thing, you\'re watching them do it. That distance lets you see patterns you normally miss. The way you hesitate before decisions, the small rituals you don\'t think about, the gap between what you intended to do and what you\'re actually doing. It\'s a ve-minute exercise in seeing yourself from the outside. Belongs with Day 35 and Day 49. Watching yourself from outside the usual angle. What did the character do that surprised the narrator? WHAT DID YOU NOTICE? WHAT DID YOU FEEL? ANYTHING ELSE? fi fi' },
  { day: 96, title: 'SIT SOMEWHERE WITH NO PHONE AND WAIT UNTIL YOUR BRAIN SHUTS UP', instr: 'You sat in silence for ten minutes much earlier in this guide. This time, sit somewhere with no phone and wait. No timer, no limit. Sit until your brain stops producing content, however long that takes.' },
  { day: 97, title: 'PICK A WORD AND SAY IT FIFTY TIMES', instr: 'Pick any word. A common one works best. Say it out loud, fty times in a row. By the twentieth it starts to sound strange. By the ftieth the meaning has separated from the sound.' },
  { day: 98, title: 'TRY TO REMEMBER YOUR DREAMS FROM LAST WEEK', instr: 'Sit down and try to recall anything you dreamed about in the past seven nights. Close your eyes. Go night by night, Monday, Tuesday, Wednesday. Try to pull something back. A face, a room, a feeling.' },
  { day: 99, title: 'SIT IN YOUR CAR IN THE DRIVEWAY. DON\'T GO ANYWHERE', instr: 'Go to your car and get in. Leave the engine, radio, and phone alone. Sit in your driveway or parking spot and be a person sitting in a car that isn\'t going anywhere.' },
  { day: 100, title: 'SCREAM INTO A PILLOW FOR TEN MINUTES', instr: 'Get a pillow. Press your face into it. Scream. Not a polite yell, a real scream. The kind you don\'t let yourself do because there\'s never a reasonable situation for it. Do it for as long as you want, up to ten minutes.' },
  { day: 101, title: 'WRITE A STRONGLY WORDED LETTER TO YOUR YOUNGER SELF', instr: 'Write a strongly worded letter to yourself at a specific age. Not the gentle, wise kind. Write the things you wish someone had told you, the things that would have changed your decisions. Be direct, don\'t soften it.' },
  { day: 102, title: 'BUILD SOMETHING OUT OF WHATEVER\'S IN YOUR JUNK DRAWER', instr: 'Open your junk drawer. The one with the batteries, the rubber bands, the mystery keys, the takeaway menus, the pen that might be dead. Build something out of what\'s in there. A sculpture, a tower, a contraption. It doesn\'t need to work or make sense.' },
  { day: 103, title: 'MAKE A LIST OF THINGS YOU PRETEND TO CARE ABOUT BUT DON\'T', instr: 'Sit down with paper. Write a list of things you perform interest in but don\'t care about. The hobby you keep claiming, the cause you post about but never act on, the thing you say you want but haven\'t moved toward. Be specific. Be ruthless.' },
  { day: 104, title: 'NAME FIVE SOUNDS YOU USUALLY IGNORE. LISTEN FOR ALL FIVE', instr: 'Right now, name ve sounds in your environment that you normally lter out. The fridge, the air conditioning, traf c, birds, your own breathing. Write them down. Then sit still and listen for all ve at once, as separate, distinct things happening together. Why this works. Your brain runs an aggressive noise lter. It ranks sounds by relevance and throws away anything that doesn\'t make the cut. That\'s ef cient but it means you\'re hearing an edited version of your life. The real soundtrack is fuller, noisier, and more alive than the one your brain presents. Listening for ve ltered sounds at once forces the volume back up on things you\'ve been silencing. Echoes Day 12. Same sound-listening muscle, different prompt. Which sound had been there the longest without you noticing? WHAT DID YOU NOTICE? WHAT DID YOU FEEL? ANYTHING ELSE? fi fi fi fi fi fi fi fi' },
  { day: 105, title: 'LISTEN TO A GENRE OF MUSIC YOU\'VE ALWAYS DISMISSED', instr: 'Pick a genre you\'ve never given a fair chance. Country, jazz, metal, classical, K-pop, opera. Whatever you\'ve always said isn\'t for you. Find a well-regarded album in that genre and listen to the whole thing as the only thing you\'re doing.' },
  { day: 106, title: 'LEARN TO SHUFFLE A DECK OF CARDS PROPERLY', instr: 'Get a deck of cards. Look up how to do a rif e shuf e, the real one where the two halves arc together in a clean bridge. Try it. It will be terrible. Do it again. Keep going until it starts to feel like something.' },
  { day: 107, title: 'NAME EVERY EMOTION YOU\'VE FELT TODAY. "FINE" DOESN\'T COUNT', instr: 'Go through your day hour by hour. For each section, name the specific emotion you were feeling. Not "good" or "bad" or " ne." The actual word. Irritated, relieved, anxious, at, amused, restless. Be as precise as you can.' },
  { day: 108, title: 'SEE HOW SLOWLY YOU CAN DRINK A GLASS OF WATER', instr: 'Fill a glass of water. Drink it as slowly as you possibly can. Not in sips. In a continuous, absurdly slow pour into your mouth. Feel the temperature, feel it move down your throat. Try to make a single glass last five minutes.' },
  { day: 109, title: 'TRY TO DRAW A PERFECT CIRCLE FREEHAND', instr: 'Get a pen and paper. Draw a circle. A perfect one. Freehand. No coins, no cups, no tracing. Just your hand and the paper. Look at it. Try again. Try ten times. Compare them.' },
  { day: 110, title: 'REMEMBER A VERSION OF YOURSELF YOU ACTUALLY LIKED. VISIT THAT PERSON', instr: 'Think back to a time when you genuinely liked who you were. A time when the way you moved through the world felt right. Visit that version. Sit with them. Remember how they thought, what they cared about, how they spent their time.' },
  { day: 111, title: 'COUNT EVERY STEP ON A WALK. FORGET THE NUMBER. START OVER', instr: 'Go for a walk. Count every step. One, two, three, four. At some point you\'ll lose the number because a thought will take over or something will catch your eye. When that happens, start back at one. Keep walking. Keep counting. Keep losing count.' },
  { day: 112, title: 'SIT IN COMPLETE DARKNESS FOR FIVE MINUTES', instr: 'Wait until it\'s dark, or find a room with no windows. Turn off every light. Sit in complete darkness for five minutes. Don\'t use your phone as a light or light a candle. Just sit with the black.' },
  { day: 113, title: 'PICK ONE BELIEF YOU HOLD AND ARGUE THE OPPOSITE. OUT LOUD', instr: 'Choose something you believe. Not a trivial thing. Something you care about. Now argue against it. Out loud. Make the best possible case for the other side. Give it everything. Pretend you\'re trying to convince someone.' },
  { day: 114, title: 'LEARN ONE MAGIC TRICK WELL ENOUGH TO FOOL SOMEONE', instr: 'Find a simple magic trick. A card trick, a coin vanish, anything with household objects. Learn it. Practise until you can do it without thinking about the steps. Then try it on someone. It doesn\'t matter if it works. The practising is the point.' },
  { day: 115, title: 'LET A MOMENT BE ENOUGH WITHOUT TURNING IT INTO CONTENT', instr: 'The next time something beautiful or interesting or funny happens, don\'t photograph it, post it, text anyone, or even mentally compose the caption. Just let the moment exist between you and itself.' },
  { day: 116, title: 'WALK TO THE FARTHEST POINT YOU CAN SEE AND THEN PICK A NEW ONE', instr: 'Stand somewhere with a view. Pick the farthest point you can see and walk to it. When you get there, pick a new farthest point. Walk to that one. Keep going until you decide to stop.' },
  { day: 117, title: 'THROW SOMETHING AWAY YOU\'VE BEEN KEEPING OUT OF GUILT', instr: 'Find the thing. The gift you never liked but kept, the clothes that don\'t t but feel wasteful to bin, the object that means nothing but feels wrong to throw away. Throw it away.' },
  { day: 118, title: 'ATTEMPT ORIGAMI WITH NO INSTRUCTIONS', instr: 'Get a piece of paper. Fold it into something. A bird, a box, a boat, anything. No tutorials, YouTube, or reference images. Just fold the paper and see what your hands come up with.' },
  { day: 119, title: 'GO SOMEWHERE ALONE THAT COUPLES USUALLY GO', instr: 'Go to a restaurant, a cinema, a park bench at sunset. Somewhere culturally coded as a "couples" spot. Go alone. Don\'t bring a book or your phone as camou age. Just be there, alone, in a space that society says you need a partner to enjoy.' },
  { day: 120, title: 'TRY TO THINK OF NOTHING FOR SIXTY SECONDS', instr: 'Set a timer for sixty seconds. Close your eyes. Try to think of absolutely nothing. Pure blankness. See how long you last before a thought appears.' },
  { day: 121, title: 'DO SOMETHING KIND FOR YOURSELF. YOU DON\'T HAVE TO EARN IT', instr: 'Today, do one kind thing for yourself. Not a reward, not a treat. Just a kind act, for no reason. Cook something you love, buy the thing, run the bath. Do it without attaching a justi cation.' },
  { day: 122, title: 'TRY TO WRITE WITH YOUR NON- DOMINANT HAND', instr: 'Get a pen and paper. Switch hands. Write a full paragraph with the hand you never write with. It will look like a child\'s handwriting. Read it back.' },
  { day: 123, title: 'IMAGINE YOUR LIFE IS A DOCUMENTARY. WHAT\'S THIS SCENE ABOUT', instr: 'Right now, wherever you are, whatever you\'re doing, pretend a camera crew is filming it. Not for drama. For a documentary. A quiet, observational one. What is this scene about? What would the audience learn about you from watching this moment?' },
  { day: 124, title: 'SIT IN A WAITING ROOM WITH NOTHING TO WAIT FOR', instr: 'Find a waiting room. A doctor\'s of ce lobby, a bus station, a laundromat, anywhere people wait. Sit there. You\'re not waiting for anything. You\'re just sitting in a room designed for waiting, without the waiting part.' },
  { day: 125, title: 'LOOK AT OLD TEXTS FROM SOMEONE YOU USED TO TALK TO. DON\'T TEXT THEM', instr: 'Open your phone. Find a conversation with someone you used to talk to all the time but don\'t anymore. Scroll through it. Read the messages. Remember the version of you that sent them. Then close the conversation and don\'t send anything.' },
  { day: 126, title: 'REORGANIZE YOUR BOOKSHELF BY COLOUR, THEN BY SIZE, THEN GIVE UP', instr: 'Take all the books off your shelf. Put them back sorted by the colour of the spine. Look at it. Then take them all off and sort by size. Look at that. Then give up entirely and put them back however they land. Leave it.' },
  { day: 127, title: 'PICK ONE ITEM YOU OWN AND REMEMBER EXACTLY HOW YOU GOT IT', instr: 'Choose an object in your home. Something you\'ve had for a while. Hold it. Try to remember the complete story of how you got it. Who gave it, where you bought it, how you found it. The day, the weather, the context, the reason.' },
  { day: 128, title: 'LOOK AT THE SKY LONG ENOUGH TO ACTUALLY SEE IT MOVE', instr: 'Go outside. Look up. Keep looking. Don\'t check the time or look at your phone. Just watch the sky. The clouds, if there are any. The light changing. The colour shifting. Stay long enough that you can actually see it moving.' },
  { day: 129, title: 'DROP EVERY LABEL FOR AN HOUR', instr: 'For the next hour, you are not your job, not someone\'s partner or child, not a creative or an introvert or an overthinker. Drop every label. For sixty minutes, you\'re just a person in a room with no title, no role, no story.' },
  { day: 130, title: 'SEE HOW MANY PUSH-UPS YOU CAN DO. SUBTRACT THE ONES THAT DIDN\'T COUNT', instr: 'Get on the floor. Do push-ups. Count them. When you\'re done, replay each one in your head and subtract the ones where your form broke, where you didn\'t go all the way down, where you cheated a little. The honest number is your number.' },
  { day: 131, title: 'TRY TO REMEMBER EVERY TEACHER YOU EVER HAD. IN ORDER', instr: 'Start from the beginning. Your first teacher. Then the next one. Then the next. Go year by year through your entire education. Name them. Picture them. Remember something about each one if you can.' },
  { day: 132, title: 'SIT STILL LONG ENOUGH THAT A BIRD FORGETS YOU\'RE THERE', instr: 'Go outside. Find a spot near where birds are. Sit completely still. Don\'t move. Wait until the birds stop registering you as a threat and go back to what they were doing. Let yourself disappear into the background of their world.' },
  { day: 133, title: 'APOLOGIZE TO YOURSELF FOR SOMETHING YOU\'VE BEEN HOLDING AGAINST YOU', instr: 'Think of something you\'ve done that you punish yourself for. A decision, a failure, a moment you\'re not proud of. Say the apology out loud. To yourself. Speci cally. Not "I forgive myself" in some general way. Name the thing. Say sorry for it. Mean it.' },
  { day: 134, title: 'WRITE A HAIKU ABOUT YOUR LUNCH. IT DOESN\'T HAVE TO BE GOOD', instr: 'Look at your lunch. Write a haiku about it. Five syllables, seven, ve. Don\'t overthink it or try to be clever. Just describe what\'s on your plate in seventeen syllables and move on.' },
  { day: 135, title: 'WRITE A GRATITUDE LIST SO LONG IT GETS EMBARRASSING. AIM FOR 50', instr: 'Sit down with paper. Start writing things you\'re grateful for. Not the big ones, not health and family. The small, specific, stupid ones. The sound a Coke makes when you open it. The fact that someone, somewhere, gured out bread. Keep going until fty.' },
  { day: 136, title: 'PICK A COLOUR. SPEND A WALK ONLY NOTICING THINGS THAT COLOUR', instr: 'Before you leave the house, pick a colour. Red, blue, yellow, anything. Then go for a walk and only notice things that colour. Postboxes, doors, owers, cars, jackets, signs. Let everything else blur into background and let your chosen colour pull your attention.' },
  { day: 137, title: 'RELEARN SOMETHING YOU USED TO KNOW', instr: 'Think of a skill you used to have that you\'ve let go. A guitar chord, a recipe you made from memory, a drive you could do without directions. Try to do it again. From memory. No looking it up.' },
  { day: 138, title: 'PUT ON A SONG AND CONDUCT AN IMAGINARY ORCHESTRA. COMMIT FULLY', instr: 'Pick a song with a big sound. Orchestral, or close enough. Stand up. Press play. Conduct. Fully. Arms out, hands moving, eyes closed if you want. Conduct the entire thing as if fty musicians are watching you and you\'re the reason they\'re playing.' },
  { day: 139, title: 'WRITE A REVIEW OF YOUR OWN LIFE SO FAR. BE FAIR', instr: 'Sit down and write a review. Like you\'d review a restaurant or a lm. Rate the major areas. The decisions, the relationships, the career, the fun, the direction. Be fair. Not generous. Not harsh. Fair. Give it a star rating if you want.' },
  { day: 140, title: 'CLOSE YOUR EYES AND TRY TO NAVIGATE YOUR HOME BY MEMORY', instr: 'Stand in one room of your home. Close your eyes. Try to walk to another room using only your memory of the layout. Keep your hands out if you want. A door frame, a corner, furniture that isn\'t where you thought.' },
  { day: 141, title: 'COMPLIMENT A STRANGER IN YOUR HEAD WITHOUT SAYING IT', instr: 'The next time you see a stranger, notice something good about them. Their shoes, their posture, the way they laugh, the fact that they\'re reading an actual book. Form the full compliment in your head. Then keep walking. Don\'t say it.' },
  { day: 142, title: 'SIT ON YOUR KITCHEN FLOOR', instr: 'Go to your kitchen. Sit on the floor, not on a chair. Look around from that height. The undersides of counters, the gap beneath the fridge, the view of the room from two feet off the ground instead of ve.' },
  { day: 143, title: 'WRITE DOWN EVERY LIE YOU TELL YOURSELF REGULARLY', instr: 'Get a piece of paper. Write down the things you tell yourself that you know aren\'t true. "I\'ll start tomorrow." "It doesn\'t bother me." "I don\'t care what people think." Be specific about the exact phrases. The ones that run on a loop.' },
  { day: 144, title: 'TIME HOW LONG YOU CAN HOLD YOUR BREATH', instr: 'Take a deep breath. Hold it. Start a timer. See how long you can go before you have to breathe. Write the number down. Tomorrow, try again.' },
  { day: 145, title: 'TRY TO DESCRIBE SOMETHING BEAUTIFUL WITHOUT USING WORDS', instr: 'Find something you think is beautiful. A view, an object, a person\'s face in a photograph. Now try to describe it without language. Draw it, hum it, move your hands, use your body. Anything except words.' },
  { day: 146, title: 'WALK TO THE NEAREST BODY OF WATER AND JUST STAND THERE', instr: 'Find water. A river, pond, lake, sea. If nothing\'s nearby, a canal will do. Stand near it and watch. Don\'t take a photo or think about your life. Just stand and let the water do its thing.' },
  { day: 147, title: 'WRITE YOUR OBITUARY. HONEST FIRST, THEN FUNNY', instr: 'Write your own obituary. Start with the honest version. What you actually did, how you spent your days, what mattered. Then rewrite it as a funny one. Same facts, different tone. Read them both.' },
  { day: 148, title: 'STARE AT YOUR HAND FOR SIXTY SECONDS', instr: 'Hold your hand in front of your face. Look at it for sixty seconds. The lines, the veins, the way the skin moves over the knuckles. Don\'t look away. By the thirty-second mark, it will start to look like it doesn\'t belong to you.' },
  { day: 149, title: 'TRY TO DRAW YOUR FACE FROM MEMORY. DON\'T CHEAT', instr: 'Get paper and a pen. Draw your own face. From memory. No mirror. No sel e. No reference. Just what you think you look like, drawn from the image in your head.' },
  { day: 150, title: 'SPEND TIME OUTSIDE AND DON\'T POST IT', instr: 'Go outside. Somewhere nice. Do something. A walk, a bench, a coffee in the sun. The only rule is that nothing about it goes online. No story, no post, no text saying "look where I am." The experience stays between you and the air.' },
  { day: 151, title: 'OPEN YOUR WARDROBE AND ASK YOURSELF WHY YOU STILL OWN THAT ONE THING', instr: 'Open your wardrobe. Don\'t look at everything. Look at the one thing you already know you\'re going to look at. The thing that doesn\'t t, that you never wear, that no longer represents you. Stand in front of it and ask why it\'s there.' },
  { day: 152, title: 'TRY TO JUGGLE WITH TWO THINGS, THEN THREE', instr: 'Find two objects that won\'t break if you drop them. Oranges, socks, tennis balls. Try to juggle with two. When that feels manageable, add a third. Drop everything, pick it up, try again. Keep going until you either get it or accept that you can\'t.' },
  { day: 153, title: 'TIME YOURSELF DOING NOTHING. SEE HOW LONG YOU LAST BEFORE YOU CHEAT', instr: 'Set a timer. Do nothing. See how many minutes pass before you cheat. You\'ll know when you cheat. A thought about work, a grocery list, a reach for your phone. Stop the timer at the first cheat.' },
  { day: 154, title: 'ADMIT WHAT KIND OF LIFE YOU ACTUALLY WANT. NOT THE POLISHED VERSION', instr: 'Sit with a piece of paper. Write down the life you want. Not the version that sounds good in conversation or ts your current trajectory. The real one. The one you think about at 2am when nobody\'s watching. Be specific. Be honest.' },
  { day: 155, title: 'SMELL EVERY CANDLE IN A SHOP. BUY THE WRONG ONE', instr: 'Go to a shop that sells candles. Smell every single one. Take your time. Find the one you like best. Then buy a different one. Take it home. Light it. Enjoy it.' },
  { day: 156, title: 'MAKE A PLAYLIST FOR A VERSION OF YOU THAT DOESN\'T EXIST YET', instr: 'Open your music app. Make a playlist. Don\'t ll it with songs you like now. Fill it with songs that belong to a future you. The one that lives somewhere else, feels something new. Build the soundtrack.' },
  { day: 157, title: 'HANDWRITE A TO-DO LIST INSTEAD OF TYPING IT', instr: 'Write your to-do list by hand today. On paper. With a pen. The same tasks you\'d normally type into your phone or your laptop. Write them out. Look at the list. Do the tasks from the paper.' },
  { day: 158, title: 'WRITE YOUR LIFE STORY IN EXACTLY SIX WORDS', instr: 'Six words. That\'s it. Summarize your entire life in six words. Not a tagline. Not a motto. A story. It should have a beginning and an end, or at least feel like it does. Write it. Read it. Decide if it\'s true.' },
  { day: 159, title: 'READ A WIKIPEDIA ARTICLE ABOUT SOMETHING YOU\'LL NEVER NEED TO KNOW', instr: 'Open Wikipedia. Click random article. Or search for something you have no reason to know about. The mating habits of octopuses. The history of Estonian currency. How suspension bridges work. Read the whole article. Not skim. Read.' },
  { day: 160, title: 'SIT QUIETLY AND ASK: "WHAT HERE IS ACTUALLY MINE?"', instr: 'Sit somewhere in your life. For each thing you see, ask: is this mine? Do you identify with it, or just own it? The job, the routine, the beliefs, the relationships. Which did you choose, and which just accumulated?' },
  { day: 161, title: 'PICK A CLOUD. WATCH IT UNTIL IT CHANGES SHAPE. NAME THE NEW SHAPE', instr: 'Go outside. Pick one cloud. Watch it. Don\'t look away. Wait until it changes shape. When it does, name the new shape. Then keep watching until it changes again. Name that one too.' },
  { day: 162, title: 'ASK A SHOP OWNER WHAT THEY LOVE ABOUT THEIR SHOP', instr: 'Find a shop you\'ve walked past but never gone into. A second-hand bookshop, a vintage store, a small bakery, a hardware shop. Walk in. Look around. Then ask the person behind the counter what they love about running it.' },
  { day: 163, title: 'LEARN TO SAY ONE SENTENCE IN A LANGUAGE NO ONE AROUND YOU SPEAKS', instr: 'Pick a language nobody in your daily life uses. Learn one sentence. Not "hello" or "thank you." An actual sentence. "The weather is nice today." "I like your shoes." Learn it well enough to say without reading.' },
  { day: 164, title: 'MEMORIZE A POEM FOR NO REASON', instr: 'Find a poem you like. A short one. Read it several times. Then try to recite it from memory. Keep practising until you can say the whole thing without looking. Then carry it around in your head like a thing you own.' },
  { day: 165, title: 'WEAR YOUR WATCH ON THE OTHER WRIST', instr: 'Switch your watch to the opposite wrist. Leave it there for the whole day. Don\'t switch it back.' },
  { day: 166, title: 'WRITE THE WORST POEM YOU CAN ON PURPOSE', instr: 'Sit down and write the worst poem you\'re capable of. Bad rhymes, cliches, forced metaphors. Make it terrible. Then read it out loud with full conviction, as if you\'re performing at a sold-out reading.' },
  { day: 167, title: 'PICK ONE OPINION YOU INHERITED AND ACTUALLY QUESTION IT', instr: 'Think of a belief you didn\'t arrive at on your own. Something your parents believed, your culture assumed, your friends treat as obvious. Pick one. Question it. Not to destroy it, but to see if it survives your own thinking.' },
  { day: 168, title: 'LEARN ONE CONSTELLATION WELL ENOUGH TO FIND IT', instr: 'Pick a constellation. One you\'ve heard of but couldn\'t point to. Orion, the Plough, Cassiopeia. Learn what it looks like and where it sits in the sky this time of year. Then go outside at night and find it.' },
  { day: 169, title: 'WATCH A DOCUMENTARY ABOUT SOMETHING YOU KNOW NOTHING ABOUT', instr: 'Find a documentary about a subject you have zero knowledge of and zero interest in. Competitive pigeon racing, Antarctic research stations, the history of fonts. The more removed from your world, the better. Watch the whole thing.' },
  { day: 170, title: 'PICK UP A ROCK. CARRY IT HOME. DON\'T EXPLAIN WHY', instr: 'While you\'re outside, find a rock that catches your eye. Pick it up. Put it in your pocket. Carry it home. Put it somewhere in your house. If anyone asks why there\'s a rock on your shelf, don\'t explain.' },
  { day: 171, title: 'EAT SOMETHING YOU HATED AS A KID', instr: 'Think of a food you refused to eat as a child. Brussels sprouts, olives, blue cheese, sh. Whatever made you gag at age eight. Get some. Eat it. Not a brave nibble. An actual portion.' },
  { day: 172, title: 'HOLD EYE CONTACT WITH YOURSELF IN THE MIRROR', instr: 'Stand in front of a mirror. Look yourself in the eyes. Not a glance. Not the quick check you do before leaving the house. Actual, sustained eye contact with your own face. Hold it for two minutes.' },
  { day: 173, title: 'PEOPLE-WATCH FROM A WINDOW. ASSIGN THEME SONGS', instr: 'Sit by a window that faces a street or a public space. Watch people walk past. For each one, assign them a theme song. The businessperson in a rush gets one song. The kid skipping gets another. Build a soundtrack for the street.' },
  { day: 174, title: 'EXPLAIN YOUR JOB TO AN IMAGINARY FIVE-YEAR-OLD', instr: 'In your head, explain what you do for a living to an imaginary ve-year- old. No jargon. No industry terms. No shortcuts. Explain it so a child would understand what you actually do all day and why anyone pays you to do it.' },
  { day: 175, title: 'PICK UP A PEN AND DRAW WHATEVER YOUR HAND WANTS', instr: 'Get a pen. Not a pencil. A pen. Something you can\'t erase. Put it to paper and draw. Don\'t plan what you\'re going to draw. Don\'t sketch an outline first. Just let your hand move and see what appears.' },
  { day: 176, title: 'WRITE A LETTER YOU\'LL NEVER SEND', instr: 'Think of someone you need to say something to. A person you\'re angry at, grateful to, confused by, or still carrying feelings about. Write them a letter. Say everything. Don\'t hold back. Then put the letter somewhere and don\'t send it.' },
  { day: 177, title: 'OPEN A RANDOM BOOK TO A RANDOM PAGE', instr: 'Pick a book from your shelf. Any book. Close your eyes and open it to a random page. Read that page. Just that one. No context. No beginning, no end. Just the page in front of you.' },
  { day: 178, title: 'WRITE A YELP REVIEW OF YOUR OWN BEDROOM', instr: 'Write a review of your bedroom as if you\'re a guest reviewing a hotel room. Rate the comfort, the lighting, the decor, the noise level, the overall vibe. Be honest. Be specific. Star rating included.' },
  { day: 179, title: 'WALK INTO A SHOP YOU\'VE NEVER ENTERED', instr: 'Find a shop you\'ve never been in. Walk in. Look around. Ask questions if you want. Touch things. Read labels. Learn something about whatever it is they sell. Then leave without buying anything.' },
  { day: 180, title: 'TASTE SOMETHING WITH YOUR EYES CLOSED', instr: 'Prepare something to eat, or have someone prepare it for you. Close your eyes. Take a bite. Try to name every ingredient you can taste. Not the dish. The individual components. Salt, garlic, butter, lemon. Something you can\'t quite place.' },
  { day: 181, title: 'WRITE DOWN WHAT ACTUALLY MATTERS TO YOU', instr: 'Sit down with paper. Write what actually matters to you. Not what should matter. Not what you\'d say at a dinner party. The things that, if they disappeared, would leave a hole you couldn\'t ll.' },
  { day: 182, title: 'MAKE YOUR BED LIKE A HOTEL', instr: 'Make your bed. Not the usual throw-the-duvet-over version. The hotel version. Crisp corners. Smooth sheets. Pillows arranged. Then stand back and look at it like you\'re about to leave a ve-star review.' },
  { day: 183, title: 'TRY TO IDENTIFY TEN BIRDS BY SOUND', instr: 'Go outside. Listen. Every bird sound you hear, try to identify it. Sparrow, pigeon, blackbird, crow, magpie, robin. Count ten distinct calls. Some you\'ll know. Some you\'ll guess. Some you\'ll get completely wrong.' },
  { day: 184, title: 'ORGANIZE ONE DRAWER LIKE YOUR SANITY DEPENDS ON IT', instr: 'Pick one drawer. The kitchen drawer, the bathroom drawer, the desk drawer. Take everything out. Clean the inside. Put everything back with a system. Groups, sections, logic. Make it unreasonably neat.' },
  { day: 185, title: 'READ THE TERMS AND CONDITIONS OF SOMETHING', instr: 'Open any app or service you use daily. Find the terms and conditions. The part you always scroll past and click "agree." Read them. Not skim. Read. See what you\'ve agreed to.' },
  { day: 186, title: 'BUY ONE INGREDIENT YOU\'VE NEVER COOKED WITH', instr: 'Go to the shop. Walk past the aisles you normally visit. Find an ingredient you\'ve never bought. Lemongrass, tahini, star anise, miso paste, pickled ginger. Buy it. Take it home. Figure out what to do with it.' },
  { day: 187, title: 'PICK A RANDOM COORDINATE ON GOOGLE EARTH', instr: 'Open Google Earth. Spin the globe. Drop a pin somewhere random. Zoom in. Look at the roads, the buildings, the landscape. Imagine the person who lives in the closest house. What\'s their morning like, what do they worry about.' },
  { day: 188, title: 'GOOGLE THE HISTORY OF A RANDOM OBJECT IN YOUR HOUSE', instr: 'Find an ordinary object. A fork, a lightbulb, a zipper, a mirror, a pencil. Google the history of that object. When was it invented. Who invented it. What existed before it. How has it changed.' },
  { day: 189, title: 'SING A SONG YOU HAVEN\'T HEARD IN TEN YEARS', instr: 'Think of a song you loved a decade ago but haven\'t listened to since. Try to sing it from memory. Don\'t look up the lyrics. Sing whatever you remember, ll in the gaps with whatever sounds right, and commit to every wrong word.' },
  { day: 190, title: 'FEEL SOMETHING WITHOUT EXPLAINING IT TO ANYONE. INCLUDING YOURSELF', instr: 'At some point today, you\'ll feel something. Not dramatic. Just a feeling. A shift, a wave. When it arrives, let it happen. Don\'t name it, analyze it, tell anyone, write about it, or narrate it in your head. Just feel it and let it pass.' },
  { day: 191, title: 'TRY TO TOUCH YOUR TOES', instr: 'Stand up. Feet together. Bend forward. Reach for your toes. See how far you get. If you can touch them, hold it. If you can\'t, notice where your body stops and feel the tension in the places that won\'t stretch.' },
  { day: 192, title: 'NAME AS MANY COUNTRIES AS YOU CAN FROM MEMORY', instr: 'Sit down with a blank piece of paper. Write the name of every country you can think of. From memory. No maps. No hints. No Googling. Just write until your brain goes blank. Then count them.' },
  { day: 193, title: 'TALK TO A PLANT', instr: 'Find a plant. Yours or someone else\'s. Talk to it. Not baby talk. Not a joke. Have an actual one-sided conversation. Tell it about your day. Complain about something. Ask it how it\'s doing.' },
  { day: 194, title: 'MEMORIZE ONE OBSCURE FACT', instr: 'Find one obscure fact. Something specific. Something nobody at a dinner table would know. The melting point of gold, the population of Iceland, the year the zipper was patented. Memorize it. Carry it around. Wait for the moment it becomes relevant. It might take years.' },
  { day: 195, title: 'LEARN TO TIE ONE KNOT YOU DON\'T ALREADY KNOW', instr: 'Look up a knot you\'ve never tied. A bowline, a clove hitch, a sheet bend. Learn the steps. Practise until you can do it without looking at the instructions. Then know a new knot for the rest of your life.' },
  { day: 196, title: 'STAND IN A DOORWAY AND REMEMBER WHAT YOU CAME IN FOR', instr: 'Walk into a room. Forget why you\'re there. This will happen naturally, probably today. When it does, don\'t leave. Don\'t check your phone. Don\'t move on to something else. Stand in the doorway and wait until your brain gives the memory back.' },
  { day: 197, title: 'WRITE A FIVE-STAR REVIEW OF A MUNDANE OBJECT', instr: 'Pick the most boring object in your home. A spatula, a doorstop, a paperclip. Write it a ve-star review as if it changed your life. Be as dramatic as possible. Superlatives, emotional language, complete devotion to this object.' },
  { day: 198, title: 'FOLD YOUR LAUNDRY IN COMPLETE SILENCE', instr: 'Do your laundry. When it\'s time to fold, turn everything off. No podcast. No music. No show running in the background. Just the folding. Feel the fabric. Match the socks. Stack the shirts. Let the task be the only thing happening.' },
  { day: 199, title: 'TRY TO WHISTLE WITH A BLADE OF GRASS', instr: 'Find a wide blade of grass. Hold it between your thumbs. Blow. The goal is to make a sound. A whistle, a squeak, anything. You will almost certainly fail. That\'s ne. Keep trying for at least five minutes.' },
  { day: 200, title: 'LIE FLAT ON YOUR BACK OUTSIDE', instr: 'Go outside. Lie on your back. Look up. The sky will look like a ceiling above you. Keep looking. At some point, the ceiling will dissolve and you\'ll feel the depth. Stay there.' },
];
